#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10,Mod=1e9+7;int fac[N],ifac[N],n,k;
inline int qpow(int a,int b=Mod-2){int res=1;while(b){if(b&1)res=1ll*res*a%Mod;a=1ll*a*a%Mod;b=b>>1;}return res;}
inline void Init(int n=2e5+5)
{
	fac[0]=1;fac[1]=1;rep(2,n,i)fac[i]=1ll*fac[i-1]*i%Mod;
	ifac[n]=qpow(fac[n]);drep(n,3,i)ifac[i-1]=1ll*ifac[i]*i%Mod;ifac[0]=ifac[1]=1;
}
inline int F(int x)
{
//	puts("QAQ")
	int tmp=qpow(x+1,n-2);
//	printf("QAQ %d %d = %d %d\n",x+1,n-2,tmp,qpow(2,2));
//	printf("%lld %d\n",1ll*tmp*(n+x)%Mod,x);
//	
	return 1ll*tmp*(n+x)%Mod;
}
int main()
{
	n=read();k=read();if(n==1)return printf("%d\n",read()),0;
	int ans=0,sm=0;rep(1,n,i){sm+=read();sm>=Mod?sm-=Mod:0;}Init();
	rep(0,k-1,j){ans=(1ll*(j&1?Mod-ifac[j]:ifac[j])*ifac[k-j-1]%Mod*F(k-j-1)+ans)%Mod;}
//	printf("%d %d %d\n",ans,sm,ifac[3]);
	printf("%lld\n",1ll*ans*sm%Mod);return 0;
}
